document.addEventListener('DOMContentLoaded', function () {

 if (window.location.pathname.indexOf('/admin') !== 0) return;


 const toastContainer = document.createElement('div');
 toastContainer.className = 'admin-alert-toast-container';
 document.body.appendChild(toastContainer);


 const processedAlertIds = new Set();

 function scanSecurityIncidentsTelemetry() {
 fetch('/api/admin/security-alerts', {
 method: 'GET',
 headers: { 'X-Requested-With': 'XMLHttpRequest' }
 })
 .then(response => {
 if (!response.ok) throw new Error('API Access unauthorized or dropped');
 return response.json();
 })
 .then(data => {
 if (data.status === 'success' && Array.isArray(data.alerts)) {
 data.alerts.forEach(alert => {
 const alertId = parseInt(alert.id, 10);
 

 if (processedAlertIds.has(alertId)) return;
 processedAlertIds.add(alertId);


 if (processedAlertIds.size > 10 && alertId) {
 spawnSecurityToastAlert(alert);
 }
 });
 }
 })
 .catch(err => console.warn('Security monitor channel disconnect:', err));
 }

 function spawnSecurityToastAlert(alert) {
 const toast = document.createElement('div');
 toast.className = 'security-alert-toast-item';
 
 toast.innerHTML = `
 <div class="security-alert-toast-header">
 <span>⚠️ КРИТИЧЕСКАЯ АКТИВНОСТЬ</span>
 <span class="security-alert-toast-time">${alert.created_at.split(' ')[1]}</span>
 </div>
 <div class="security-alert-toast-body">
 <strong>Действие:</strong> ${alert.action}<br>
 ${alert.description}<br>
 <strong>Атакующий IP:</strong> <span class="security-alert-toast-ip">${alert.ip_address}</span>
 </div>
 `;

 toastContainer.appendChild(toast);


 setTimeout(() => {
 toast.style.opacity = '0';
 toast.style.transform = 'translateY(-10px)';
 toast.style.transition = 'all 0.4s ease';
 setTimeout(() => toast.remove(), 400);
 }, 8000);
 }


 scanSecurityIncidentsTelemetry();
 setInterval(scanSecurityIncidentsTelemetry, 10000);
});

;


;


document.addEventListener('DOMContentLoaded', function () {
 const badge = document.getElementById('unread-messages-badge');
 if (!badge) return; // Exit immediately if the user is a guest (no badge present)

 
 function pollUnreadMessageCount() {
 fetch('/api/messages/unread-count', {
 method: 'GET',
 headers: {
 'X-Requested-With': 'XMLHttpRequest'
 }
 })
 .then(response => {
 if (!response.ok) throw new Error('Network notification tracking failure');
 return response.json();
 })
 .then(data => {
 if (data.status === 'success') {
 const count = parseInt(data.count, 10);
 
 if (count > 0) {
 badge.innerText = count;
 badge.classList.remove('badge-hidden');
 } else {
 badge.innerText = '0';
 badge.classList.add('badge-hidden');
 }
 }
 })
 .catch(error => {
 console.error('Polling notifications tracker issue:', error);
 });
 }


 setInterval(pollUnreadMessageCount, 15000);
});

;

document.addEventListener('DOMContentLoaded', function () {
 
 
 document.addEventListener('submit', function (event) {
 const form = event.target;
 


 if (form.action && form.action.indexOf('/vote/') !== -1) {
 return true;
 }
 

 if (form.dataset.isSubmitting === 'true') {
 event.preventDefault();
 return false;
 }


 if (form.classList.contains('js-comment-delete-form')) {
 const confirmed = confirm('Вы уверены, что хотите удалить этот комментарий?');
 if (!confirmed) {
 event.preventDefault();
 return false;
 }
 }


 form.dataset.isSubmitting = 'true';


 const submitBtn = form.querySelector('button[type="submit"]');
 if (submitBtn) {
 submitBtn.disabled = true;
 submitBtn.classList.add('btn-processing-disabled');
 }
 });
 
 
 const replyButtons = document.querySelectorAll('.comment-reply-link');
 const editButtons = document.querySelectorAll('.comment-edit-trigger');
 
 const parentIdInput = document.getElementById('form-parent-id');
 const formTitle = document.getElementById('comment-form-title');
 const cancelBtn = document.getElementById('btn-cancel-reply');
 const commentForm = document.getElementById('main-comment-form');
 const textarea = document.getElementById('form-comment-textarea');


 if (commentForm) {
 replyButtons.forEach(button => {
 button.addEventListener('click', function (e) {
 e.preventDefault();
 

 document.querySelectorAll('.comment-dynamic-edit-form').forEach(f => f.remove());
 document.querySelectorAll('.comment-text').forEach(t => t.style.display = 'block');

 const commentId = this.getAttribute('href').replace('#reply-to-', '');
 const authorName = this.closest('.comment-wrapper').querySelector('.comment-meta strong').innerText;

 parentIdInput.value = commentId;
 formTitle.innerText = `Ответ пользователю ${authorName}`;
 cancelBtn.style.display = 'inline-block';

 this.closest('.comment-node').insertBefore(commentForm, this.nextSibling);
 textarea.focus();
 });
 });

 cancelBtn.addEventListener('click', function () {
 parentIdInput.value = '';
 formTitle.innerText = 'Оставить комментарий';
 cancelBtn.style.display = 'none';
 document.querySelector('.comments-section').appendChild(commentForm);
 textarea.value = '';
 });
 }


 editButtons.forEach(button => {
 button.addEventListener('click', function (e) {
 e.preventDefault();
 
 const commentId = this.getAttribute('data-id');
 const wrapper = this.closest('.comment-wrapper');
 const textBlock = document.getElementById(`comment-text-content-${commentId}`);
 

 if (wrapper.querySelector('.comment-dynamic-edit-form')) return;


 textBlock.style.display = 'none';


 const currentText = textBlock.innerHTML.replace(/<br\s*\/?>/mg, "\n").trim();


 const csrfToken = document.querySelector('input[name="csrf_token"]').value;


 const editForm = document.createElement('form');
 editForm.action = `/comments/${commentId}/edit`;
 editForm.method = 'POST';
 editForm.className = 'comment-dynamic-edit-form comment-edit-form-node';

 editForm.innerHTML = `
 <input type="hidden" name="csrf_token" value="${csrfToken}">
 <textarea name="comment_text" required class="comment-input-textarea" style="min-height:70px; margin-bottom:5px;">${currentText}</textarea>
 <div style="display:flex; gap:10px;">
 <button type="submit" class="btn-submit-comment" style="padding:5px 10px; font-size:12px;">Сохранить</button>
 <button type="button" class="btn-cancel-reply-node comment-edit-cancel" style="padding:5px 10px; font-size:12px;">Отмена</button>
 </div>
 `;


 textBlock.parentNode.insertBefore(editForm, textBlock.nextSibling);


 editForm.querySelector('.comment-edit-cancel').addEventListener('click', function() {
 editForm.remove();
 textBlock.style.display = 'block';
 });
 });
 });
 
 

 document.addEventListener('submit', function (event) {

 if (event.target && event.target.classList.contains('js-comment-delete-form')) {
 const confirmed = confirm('Вы уверены, что хотите удалить этот комментарий?');
 if (!confirmed) {
 event.preventDefault(); // Halt the submission process if the user cancels
 }
 }
 });
 
});

 
;


document.addEventListener('DOMContentLoaded', function () {

 const registerForm = document.querySelector('form[action="/register"]');
 const loginForm = document.querySelector('form[action="/login"]');

 
 function showError(form, message) {

 let oldAlert = form.querySelector('.js-error-alert');
 if (oldAlert) oldAlert.remove();


 const alertDiv = document.createElement('div');
 alertDiv.className = 'js-error-alert';
 alertDiv.style.color = '#e74c3c';
 alertDiv.style.background = '#fdf2f2';
 alertDiv.style.padding = '10px';
 alertDiv.style.border = '1px solid #f8b4b4';
 alertDiv.style.marginBottom = '15px';
 alertDiv.style.borderRadius = '4px';
 alertDiv.style.fontSize = '14px';
 alertDiv.innerText = message;


 form.insertBefore(alertDiv, form.firstChild);
 }


 if (registerForm) {
 registerForm.addEventListener('submit', function (event) {
 const nameInput = registerForm.querySelector('input[name="name"]');
 const emailInput = registerForm.querySelector('form input[name="email"]');
 const passwordInput = registerForm.querySelector('input[name="password"]');


 if (nameInput && nameInput.value.trim().length < 2) {
 event.preventDefault(); // Halt form submission cycle
 showError(registerForm, 'Имя пользователя должно быть не менее 2 символов.');
 nameInput.focus();
 return;
 }


 const emailRegEx = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
 if (emailInput && !emailRegEx.test(emailInput.value.trim())) {
 event.preventDefault();
 showError(registerForm, 'Пожалуйста, введите корректный email адрес.');
 emailInput.focus();
 return;
 }


 if (passwordInput && passwordInput.value.length < 6) {
 event.preventDefault(); 
 showError(registerForm, 'Пароль должен состоять минимум из 6 символов.');
 passwordInput.focus();
 return;
 }
 });
 }


 if (loginForm) {
 loginForm.addEventListener('submit', function (event) {
 const passwordInput = loginForm.querySelector('input[name="password"]');

 if (passwordInput && passwordInput.value.length < 6) {
 event.preventDefault();
 showError(loginForm, 'Введен слишком короткий пароль. Минимум — 6 символов.');
 passwordInput.focus();
 return;
 }
 });
 }
});

;


document.addEventListener('DOMContentLoaded', function () {
 const trigger = document.getElementById('user-dropdown-trigger');
 const menu = document.getElementById('user-dropdown-menu');
 const wrapper = document.getElementById('user-dropdown-wrapper');

 if (!trigger || !menu) return; // Выходим, если пользователь — гость


 trigger.addEventListener('click', function (event) {
 event.stopPropagation(); // Предотвращаем всплытие события вверх к документу
 
 const isActive = menu.classList.contains('active');
 
 if (isActive) {
 menu.classList.remove('active');
 wrapper.classList.remove('active');
 trigger.setAttribute('aria-expanded', 'false');
 } else {
 menu.classList.add('active');
 wrapper.classList.add('active');
 trigger.setAttribute('aria-expanded', 'true');
 }
 });


 document.addEventListener('click', function (event) {

 if (!wrapper.contains(event.target)) {
 if (menu.classList.contains('active')) {
 menu.classList.remove('active');
 wrapper.classList.remove('active');
 trigger.setAttribute('aria-expanded', 'false');
 }
 }
 });
});

;


